sql:
SELECT COUNT(*) 
FROM weapon_loot_pool 
WHERE loot_pool_id = 1;

SELECT COUNT(*) AS fusion_rifle_count
FROM archetypes
WHERE category = 'Fusion Rifle';

SELECT rarity_name, description, drop_rate, COUNT(*) AS number_of_occurrences
FROM rarity
GROUP BY rarity_name, description, drop_rate;

SELECT category, COUNT(archetype_id) AS archetype_count
FROM archetypes
GROUP BY category;

SELECT archetype_name
FROM archetypes
WHERE archetype_id = 0;

SELECT COUNT(login_id) AS total_logins
FROM login_history
WHERE login_date BETWEEN '2023-01-01' AND '2023-12-31';

SELECT tier_id, tier_name, description
FROM tiers
WHERE tier_rank > 0;

SELECT COUNT(DISTINCT user_id) AS user_count
FROM user_progress
WHERE weapon_id = 1;

SELECT tier_name
FROM tiers
WHERE tier_rank = 1;

SELECT excel_type, COUNT(excel_name) AS excel_count
FROM excels
GROUP BY excel_type;

SELECT tier_name, COUNT(tier_id) AS tier_count
FROM tiers
GROUP BY tier_name;
